from collections import Counter

def solve(n, m, grid):
    cnt = Counter()
    for i in range(n):
        cnt[tuple(grid[i])] += 1
    for j in range(m):
        cnt[tuple(grid[i][j] for i in range(n))] += 1
    return sum(cnt.values())

def main():
    n, m = map(int, input().split())
    grid = [list(map(int, input().split())) for _ in range(n)]
    print(solve(n, m, grid))

if __name__ == "__main__":
    main()
